package com.hospital.management.service.impl;
import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.AppointmentAvailabilityService;import com.hospital.management.util.TimeSlotGenerator;import org.slf4j.*;import java.sql.SQLException;import java.time.*;import java.util.*;
/** Generates schedule-backed slots and removes active bookings and elapsed same-day slots. */
public class AppointmentAvailabilityServiceImpl implements AppointmentAvailabilityService {private static final Logger LOG=LoggerFactory.getLogger(AppointmentAvailabilityServiceImpl.class);private final DoctorScheduleDao schedules;private final AppointmentDao appointments;private final DoctorDao doctors;private final Clock clock;public AppointmentAvailabilityServiceImpl(){this(new DoctorScheduleDaoImpl(),new AppointmentDaoImpl(),new DoctorDaoImpl(),Clock.systemDefaultZone());}public AppointmentAvailabilityServiceImpl(DoctorScheduleDao s,AppointmentDao a,DoctorDao d){this(s,a,d,Clock.systemDefaultZone());}public AppointmentAvailabilityServiceImpl(DoctorScheduleDao s,AppointmentDao a,DoctorDao d,Clock c){schedules=s;appointments=a;doctors=d;clock=c;}
public List<AvailableSlot> getAvailableSlots(Long doctorId,LocalDate date,Long exclude){LocalDate today=LocalDate.now(clock);if(doctorId==null||doctorId<=0||date==null||date.isBefore(today))return List.of();try{Doctor d=doctors.findById(doctorId).orElse(null);if(d==null||!"ACTIVE".equals(d.getStatus())||!"ACTIVE".equals(d.getUserStatus()))return List.of();String weekday=date.getDayOfWeek().name();List<DoctorSchedule>windows=schedules.findAvailableByDoctorAndDay(doctorId,weekday);if(windows==null)windows=List.of();Set<LocalTime>booked=new HashSet<>(Optional.ofNullable(appointments.findBookedStartTimes(doctorId,date)).orElse(List.of()));if(exclude!=null)appointments.findById(exclude).filter(a->doctorId.equals(a.getDoctorId())&&date.equals(a.getAppointmentDate())).ifPresent(a->booked.remove(a.getStartTime()));Map<LocalTime,AvailableSlot>slots=new TreeMap<>();int candidates=0;LocalTime now=LocalTime.now(clock);for(DoctorSchedule window:windows){List<LocalTime>generated=TimeSlotGenerator.generateSlots(window.getStartTime(),window.getEndTime(),window.getSlotDurationMinutes());candidates+=generated.size();for(LocalTime start:generated)if(!booked.contains(start)&&(!date.equals(today)||start.isAfter(now)))slots.putIfAbsent(start,new AvailableSlot(start,start.plusMinutes(window.getSlotDurationMinutes()),window.getSlotDurationMinutes()));}LOG.info("Appointment availability doctorId={} appointmentDate={} weekday={} schedules={} candidateSlots={} bookedSlots={} returnedSlots={}",doctorId,date,weekday,windows.size(),candidates,booked.size(),slots.size());return List.copyOf(slots.values());}catch(SQLException|RuntimeException e){LOG.error("Appointment availability lookup failed",e);return List.of();}}}
